+impl Module for LPPool2d {
+    fn forward(
+        &self,
+        session: &mut FrankenTorchSession,
+        input: TensorNodeId,
+    ) -> Result<TensorNodeId, AutogradError> {
+        let (vals, shape) = {
+            let (v, m) = session.tensor_values_meta(input)?;
+            (v, m.shape().to_vec())
+        };
+
